import { useEffect, useState } from "react";
import {
  Box,
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Snackbar,
  Alert,
  MenuItem,
} from "@mui/material";
import API from "../../api/axios";

export default function CreateProjectUser() {
  const [form, setForm] = useState({
    username: "",
    password: "",
    confirmPassword: "",
    role: "",
    project_id: "",
  });

  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(false);

  const [snackbar, setSnackbar] = useState({
    open: false,
    message: "",
    severity: "success",
  });

  // 🔥 FETCH PROJECT LIST
  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const res = await API.get("projects/");
        setProjects(res.data);
      } catch (err) {
        console.log(err);
      }
    };

    fetchProjects();
  }, []);

  const handleChange = (field) => (e) => {
    setForm({ ...form, [field]: e.target.value });
  };

  const handleCreateUser = async () => {
    if (loading) return;

    if (form.password !== form.confirmPassword) {
      return setSnackbar({
        open: true,
        message: "Passwords do not match ❌",
        severity: "error",
      });
    }

    if (!form.role || !form.project_id) {
      return setSnackbar({
        open: true,
        message: "Select role and project ❌",
        severity: "error",
      });
    }

    try {
      setLoading(true);

      await API.post("create-user/", {
        username: form.username,
        password: form.password,
        role: form.role,
        project_id: form.project_id,
      });

      setSnackbar({
        open: true,
        message: "User Created Successfully ✅",
        severity: "success",
      });

      setForm({
        username: "",
        password: "",
        confirmPassword: "",
        role: "",
        project_id: "",
      });
    } catch (err) {
      console.log(err.response);
      setSnackbar({
        open: true,
        message: err.response?.data?.error || "Error creating user ❌",
        severity: "error",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ display: "flex", justifyContent: "center", mt: 5 }}>
      <Card sx={{ p: 4, width: 400 }}>
        <CardContent>
          <Typography variant="h6" mb={2}>
            Create Project User
          </Typography>

          {/* USERNAME */}
          <TextField
            fullWidth
            label="Username"
            margin="normal"
            value={form.username}
            onChange={handleChange("username")}
          />

          {/* PASSWORD */}
          <TextField
            fullWidth
            label="Password"
            type="password"
            margin="normal"
            value={form.password}
            onChange={handleChange("password")}
          />

          {/* CONFIRM PASSWORD */}
          <TextField
            fullWidth
            label="Confirm Password"
            type="password"
            margin="normal"
            value={form.confirmPassword}
            onChange={handleChange("confirmPassword")}
          />

          {/* 🔥 ROLE DROPDOWN */}
          <TextField
            select
            fullWidth
            label="Select Role"
            margin="normal"
            value={form.role}
            onChange={handleChange("role")}
          >
            <MenuItem value="project_manager">Project Manager</MenuItem>
            <MenuItem value="project_engineer">Project Engineer</MenuItem>
            <MenuItem value="data_contributor">Data Contributor</MenuItem>
          </TextField>

          {/* 🔥 PROJECT DROPDOWN */}
          {/* <TextField
            select
            fullWidth
            label="Select Project"
            margin="normal"
            value={form.project_id}
            onChange={handleChange("project_id")}
          >
            {projects.map((proj) => (
              <MenuItem key={proj.id} value={proj.id}>
                {proj.project_name || proj.name}
              </MenuItem>
            ))}
          </TextField> */}

          {/* BUTTON */}
          <Button
            fullWidth
            variant="contained"
            sx={{ mt: 2 }}
            onClick={handleCreateUser}
            disabled={loading}
          >
            {loading ? "Creating..." : "Create User"}
          </Button>
        </CardContent>
      </Card>

      {/* SNACKBAR */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.severity}>{snackbar.message}</Alert>
      </Snackbar>
    </Box>
  );
}
